    const PRIMARY_CATS_TO_IGNORE_MISSING_PHONE_URL = [CAT.ISLAND, CAT.SEA_LAKE_POOL, CAT.RIVER_STREAM, CAT.CANAL, CAT.JUNCTION_INTERCHANGE, CAT.SCENIC_LOOKOUT_VIEWPOINT];
