    const CATS_TO_IGNORE_CUSTOMER_PARKING_HIGHLIGHT = [CAT.BRIDGE, CAT.CANAL, CAT.CHARGING_STATION, CAT.CONSTRUCTION_SITE, CAT.ISLAND, CAT.JUNCTION_INTERCHANGE, CAT.NATURAL_FEATURES, CAT.PARKING_LOT, CAT.RESIDENCE_HOME, CAT.RIVER_STREAM, CAT.SEA_LAKE_POOL, CAT.SWAMP_MARSH, CAT.TUNNEL];
    const SEARCH_RESULTS_WINDOW_NAME = '"WMEPH Search Results"';
    const _searchResultsWindowSpecs = `"resizable=yes, top=${Math.round(window.screen.height * 0.1)}, left=${Math.round(window.screen.width * 0.3)}, width=${Math.round(window.screen.width * 0.7)}, height=${Math.round(window.screen.height * 0.8)}"`;
