    const SHORTCUT = {
        allShortcuts: {},
        add(shortcutCombo, callback, opt) {
            const defaultOptions = { type: 'keydown', propagate: false, disableInInput: false, target: document, keycode: false };
            if (!opt)
                opt = defaultOptions;
            else
                Object.keys(defaultOptions).forEach(dfo => { if (typeof opt[dfo] === 'undefined')
                    opt[dfo] = defaultOptions[dfo]; });
            let ele = opt.target;
            if (typeof opt.target === 'string')
                ele = document.getElementById(opt.target);
            shortcutCombo = shortcutCombo.toLowerCase();
            const func = function (e) {
                e = e || window.event;
                if (opt.disableInInput) {
                    let element = e.target || e.srcElement;
                    if (element.nodeType === 3)
                        element = element.parentNode;
                    if (element.tagName === 'INPUT' || element.tagName === 'TEXTAREA')
                        return;
                }
                const code = e.keyCode || e.which;
                let character = String.fromCharCode(code).toLowerCase();
                if (code === 188)
                    character = ',';
                if (code === 190)
                    character = '.';
                const keys = shortcutCombo.split('+');
                let kp = 0;
                const shiftNums = { '`': '~', 1: '!', 2: '@', 3: '#', 4: '$', 5: '%', 6: '^', 7: '&', 8: '*', 9: '(', 0: ')', '-': '_', '=': '+', ';': ':', '\'': '"', ',': '<', '.': '>', '/': '?', '\\': '|' };
                const specialKeys = { esc: 27, escape: 27, tab: 9, space: 32, return: 13, enter: 13, backspace: 8, scrolllock: 145, scroll_lock: 145, scroll: 145, capslock: 20, caps_lock: 20, caps: 20, numlock: 144, num_lock: 144, num: 144, pause: 19, break: 19, insert: 45, home: 36, delete: 46, end: 35, pageup: 33, page_up: 33, pu: 33, pagedown: 34, page_down: 34, pd: 34, left: 37, up: 38, right: 39, down: 40, f1: 112, f2: 113, f3: 114, f4: 115, f5: 116, f6: 117, f7: 118, f8: 119, f9: 120, f10: 121, f11: 122, f12: 123 };
                const modifiers = { shift: { wanted: false, pressed: false }, ctrl: { wanted: false, pressed: false }, alt: { wanted: false, pressed: false }, meta: { wanted: false, pressed: false } };
                if (e.ctrlKey)
                    modifiers.ctrl.pressed = true;
                if (e.shiftKey)
                    modifiers.shift.pressed = true;
                if (e.altKey)
                    modifiers.alt.pressed = true;
                if (e.metaKey)
                    modifiers.meta.pressed = true;
                for (let i = 0; i < keys.length; i++) {
                    const k = keys[i];
                    if (k === 'ctrl' || k === 'control') {
                        kp++;
                        modifiers.ctrl.wanted = true;
                    }
                    else if (k === 'shift') {
                        kp++;
                        modifiers.shift.wanted = true;
                    }
                    else if (k === 'alt') {
                        kp++;
                        modifiers.alt.wanted = true;
                    }
                    else if (k === 'meta') {
                        kp++;
                        modifiers.meta.wanted = true;
                    }
                    else if (k.length > 1) {
                        if (specialKeys[k] === code)
                            kp++;
                    }
                    else if (opt.keycode) {
                        if (opt.keycode === code)
                            kp++;
                    }
                    else if (character === k) {
                        kp++;
                    }
                    else if (shiftNums[character] && e.shiftKey) {
                        character = shiftNums[character];
                        if (character === k)
                            kp++;
                    }
                }
                if (kp === keys.length && modifiers.ctrl.pressed === modifiers.ctrl.wanted && modifiers.shift.pressed === modifiers.shift.wanted && modifiers.alt.pressed === modifiers.alt.wanted && modifiers.meta.pressed === modifiers.meta.wanted) {
                    callback(e);
                    if (!opt.propagate) {
                        e.cancelBubble = true;
                        e.returnValue = false;
                        if (e.stopPropagation) {
                            e.stopPropagation();
                            e.preventDefault();
                        }
                        return false;
                    }
                }
            };
            this.allShortcuts[shortcutCombo] = { callback: func, target: ele, event: opt.type };
            if (ele.addEventListener)
                ele.addEventListener(opt.type, func, false);
            else if (ele.attachEvent)
                ele.attachEvent(`on${opt.type}`, func);
            else
                ele[`on${opt.type}`] = func;
        },
        remove(shortcutCombo) {
            shortcutCombo = shortcutCombo.toLowerCase();
            const binding = this.allShortcuts[shortcutCombo];
            delete (this.allShortcuts[shortcutCombo]);
            if (!binding)
                return;
            const type = binding.event;
            const ele = binding.target;
            const { callback } = binding;
            if (ele.detachEvent)
                ele.detachEvent(`on${type}`, callback);
            else if (ele.removeEventListener)
                ele.removeEventListener(type, callback, false);
            else
                ele[`on${type}`] = false;
        }
    };
